async (page) => {
  // Check what __clickEntity does and inspect game.getEntityAt
  const info = await page.evaluate(() => {
    // Check how __clickEntity works
    const clickEntityFn = window.__clickEntity ? window.__clickEntity.toString().slice(0, 600) : 'not found';

    // Check getEntityAt
    const getEntityAtFn = window.game.getEntityAt ? window.game.getEntityAt.toString().slice(0, 400) : 'not found';

    // Try calling getEntityAt with a known Snek position from state
    const s = window.__latestGameState;
    const snek = s.nearby_entities.find(e => e.name === 'Snek');
    let snekFound = 'no snek in state';
    if (snek) {
      const entity = window.game.getEntityAt(snek.x, snek.y);
      snekFound = entity ? { name: entity.name, x: entity.gridX, y: entity.gridY, type: entity.type } : `null at (${snek.x},${snek.y})`;
    }

    // Check loitering XP to confirm level increase source
    const p = window.game.player;
    const loitering = p.skills[Object.keys(p.skills).find(k => p.skills[k].name === 'Loitering')];

    return { clickEntityFn, getEntityAtFn: getEntityAtFn.slice(0, 300), snekFound, loiteringXp: loitering ? loitering.experience : 'not found', pos: s.player_position };
  });
  return JSON.stringify(info, null, 2);
}

async (page) => {
  const info = await page.evaluate(() => {
    const w = window.game.player.getWeapon();

    // Get all properties of the weapon
    const props = {};
    Object.getOwnPropertyNames(w).forEach(k => {
      const val = w[k];
      if (typeof val !== 'function') props[k] = val;
    });

    // Check attackStyles (the plural) 
    let proto = Object.getPrototypeOf(w);
    const weapMethods = [];
    while (proto && proto !== Object.prototype) {
      Object.getOwnPropertyNames(proto).forEach(k => weapMethods.push(k));
      proto = Object.getPrototypeOf(proto);
    }

    return { weaponProps: props, weaponMethods: weapMethods.slice(0, 20) };
  });
  return JSON.stringify(info, null, 2);
}

async (page) => {
  // Navigate deeper into village area
  await page.evaluate(() => { window.game.player.disableAction = false; window.game.input.keyMovement = false; });
  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 190, y: 155});
  await page.waitForTimeout(3000);

  // Check for Sorcerer and other quest NPCs in state
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const npcs = parsed.nearby_entities.filter(e => e.type === 1);
  const pos = parsed.player_position;

  return JSON.stringify({ pos, npcs: npcs.map(n => ({name: n.name, x: n.x, y: n.y, dist: n.distance, quest: n.quest_npc})) }, null, 2);
}

