async (page) => {
  await page.evaluate(() => { window.game.player.disableAction = false; window.game.input.keyMovement = false; });

  // Walk to Village Girl (136,146)
  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 136, y: 146});
  await page.waitForTimeout(3000);

  const pos = await page.evaluate(() => window.__latestGameState.player_position);

  // Get Village Girl's instance ID from nearby_entities
  const vgId = await page.evaluate(() => {
    const s = window.__latestGameState;
    const vg = s.nearby_entities.find(e => e.name === 'Village Girl');
    return vg ? { id: vg.id, dist: vg.distance, x: vg.x, y: vg.y } : null;
  });

  return JSON.stringify({ pos, vgId });
}

